import { promises as fs } from "node:fs";
import path from "node:path";

const GENERATED_ROOT = path.resolve(process.cwd(), "lib/generated");
const ENDPOINTS_DIR = path.join(GENERATED_ROOT, "endpoints");
const SERVICES_DIR = path.join(GENERATED_ROOT, "services");
const HOOKS_DIR = path.join(GENERATED_ROOT, "hooks");
const TYPES_DIR = path.join(GENERATED_ROOT, "types");
const LAYERED_ROOT_ENTRIES = new Set(["endpoints", "types", "hooks", "services"]);

const FILE_HEADER = `/**
 * Generated by scripts/generate-orval-layered-exports.mjs
 * Do not edit manually.
 */
`;

const HOOK_NAME_PATTERNS = [
  /^use[A-Z0-9_]/,
  /^get[A-Za-z0-9_]+(?:QueryKey|QueryOptions|MutationOptions)$/,
  /(?:Query|Mutation)(?:Result|Error|Body|Options|Key|Fn)?$/,
  /(?:InfiniteQuery|SuspenseQuery|SuspenseInfiniteQuery)/,
  /Prefetch/,
  /Invalidate/,
];

const exists = async (targetPath) => {
  try {
    await fs.access(targetPath);
    return true;
  } catch {
    return false;
  }
};

const removeIfExists = async (targetPath) => {
  if (!(await exists(targetPath))) return;
  await fs.rm(targetPath, { recursive: true, force: true });
};

const uniqueSorted = (values) => {
  return [...new Set(values)].sort((a, b) => a.localeCompare(b));
};

const isHookRelatedExport = (name) => {
  return HOOK_NAME_PATTERNS.some((pattern) => pattern.test(name));
};

const extractExports = (source) => {
  const declarations = [];

  const declarationRegex =
    /^export\s+(type|interface|enum|const|function|class)\s+([A-Za-z_$][A-Za-z0-9_$]*)/gm;
  for (const match of source.matchAll(declarationRegex)) {
    const kind = match[1];
    const name = match[2];
    const isTypeOnly = kind === "type" || kind === "interface";
    declarations.push({ name, isTypeOnly });
  }

  const reExportRegex = /^export\s*{\s*([^}]+)\s*};?/gm;
  for (const match of source.matchAll(reExportRegex)) {
    const rawSpecifiers = match[1]
      .split(",")
      .map((item) => item.trim())
      .filter(Boolean);

    for (const rawSpecifier of rawSpecifiers) {
      const withoutAlias = rawSpecifier
        .replace(/\s+as\s+[A-Za-z_$][A-Za-z0-9_$]*$/, "")
        .trim();
      const isTypeOnly = withoutAlias.startsWith("type ");
      const name = withoutAlias.replace(/^type\s+/, "").trim();
      if (name) declarations.push({ name, isTypeOnly });
    }
  }

  const declarationMap = new Map();
  for (const declaration of declarations) {
    if (!declarationMap.has(declaration.name)) {
      declarationMap.set(declaration.name, declaration);
    }
  }

  return [...declarationMap.values()].sort((a, b) =>
    a.name.localeCompare(b.name),
  );
};

const buildExportModule = ({ importPath, symbols }) => {
  const valueExports = uniqueSorted(
    symbols.filter((symbol) => !symbol.isTypeOnly).map((symbol) => symbol.name),
  );
  const typeExports = uniqueSorted(
    symbols.filter((symbol) => symbol.isTypeOnly).map((symbol) => symbol.name),
  );

  const lines = [FILE_HEADER.trimEnd()];

  if (valueExports.length) {
    lines.push(`export { ${valueExports.join(", ")} } from '${importPath}';`);
  }

  if (typeExports.length) {
    lines.push(`export type { ${typeExports.join(", ")} } from '${importPath}';`);
  }

  if (!valueExports.length && !typeExports.length) {
    lines.push("export {};");
  }

  return `${lines.join("\n")}\n`;
};

const buildIndexFile = (relativePaths) => {
  const exportsList = uniqueSorted(relativePaths);
  const lines = [FILE_HEADER.trimEnd()];

  if (exportsList.length) {
    for (const relativePath of exportsList) {
      lines.push(`export * from '${relativePath}';`);
    }
  } else {
    lines.push("export {};");
  }

  return `${lines.join("\n")}\n`;
};

const discoverEndpointTargets = async () => {
  if (!(await exists(ENDPOINTS_DIR))) return [];

  const directoryEntries = await fs.readdir(ENDPOINTS_DIR, { withFileTypes: true });
  const tags = directoryEntries
    .filter((entry) => entry.isDirectory())
    .map((entry) => entry.name)
    .sort((a, b) => a.localeCompare(b));

  const targets = [];

  for (const tag of tags) {
    const preferredFile = path.join(ENDPOINTS_DIR, tag, `${tag}.ts`);
    if (await exists(preferredFile)) {
      targets.push({ tag, absolutePath: preferredFile, moduleName: tag });
      continue;
    }

    const tagEntries = await fs.readdir(path.join(ENDPOINTS_DIR, tag), {
      withFileTypes: true,
    });
    const fallback = tagEntries
      .filter(
        (entry) =>
          entry.isFile() && entry.name.endsWith(".ts") && entry.name !== "index.ts",
      )
      .map((entry) => entry.name)
      .sort((a, b) => a.localeCompare(b))[0];

    if (fallback) {
      const moduleName = fallback.replace(/\.ts$/, "");
      targets.push({
        tag,
        absolutePath: path.join(ENDPOINTS_DIR, tag, fallback),
        moduleName,
      });
    }
  }

  return targets;
};

const cleanupLegacyLayout = async () => {
  if (!(await exists(GENERATED_ROOT))) return;

  const entries = await fs.readdir(GENERATED_ROOT, { withFileTypes: true });
  await Promise.all(
    entries.map(async (entry) => {
      const absolutePath = path.join(GENERATED_ROOT, entry.name);

      if (entry.isDirectory() && !LAYERED_ROOT_ENTRIES.has(entry.name)) {
        await removeIfExists(absolutePath);
        return;
      }

      if (entry.isFile() && entry.name !== "index.ts") {
        await fs.rm(absolutePath, { force: true });
      }
    }),
  );
};

const clearGeneratedWrappers = async () => {
  await removeIfExists(HOOKS_DIR);
  await removeIfExists(SERVICES_DIR);
  await fs.mkdir(HOOKS_DIR, { recursive: true });
  await fs.mkdir(SERVICES_DIR, { recursive: true });

  if (await exists(ENDPOINTS_DIR)) {
    await fs.rm(path.join(ENDPOINTS_DIR, "index.ts"), { force: true });
    const endpointEntries = await fs.readdir(ENDPOINTS_DIR, { withFileTypes: true });
    await Promise.all(
      endpointEntries.map(async (entry) => {
        if (!entry.isDirectory()) return;
        const entryPath = path.join(ENDPOINTS_DIR, entry.name);
        const indexPath = path.join(entryPath, "index.ts");
        await fs.rm(indexPath, { force: true });
        const remaining = await fs.readdir(entryPath);
        if (remaining.length === 0) {
          await fs.rm(entryPath, { recursive: true, force: true });
        }
      }),
    );
  }

  await fs.rm(path.join(TYPES_DIR, "index.ts"), { force: true });
  await fs.rm(path.join(GENERATED_ROOT, "index.ts"), { force: true });
};

const writeTypeIndex = async () => {
  await fs.mkdir(TYPES_DIR, { recursive: true });

  const typeExports = [];
  if (await exists(path.join(TYPES_DIR, "model", "index.ts"))) {
    typeExports.push("./model");
  }
  if (await exists(path.join(TYPES_DIR, "operations", "index.ts"))) {
    typeExports.push("./operations");
  }

  await fs.writeFile(path.join(TYPES_DIR, "index.ts"), buildIndexFile(typeExports));
};

const run = async () => {
  await cleanupLegacyLayout();
  await clearGeneratedWrappers();

  const endpointTargets = await discoverEndpointTargets();

  await fs.mkdir(ENDPOINTS_DIR, { recursive: true });

  const serviceIndexExports = [];
  const hookIndexExports = [];
  const endpointIndexExports = [];

  for (const target of endpointTargets) {
    const source = await fs.readFile(target.absolutePath, "utf8");
    const exportedSymbols = extractExports(source);

    const hookSymbols = exportedSymbols.filter((symbol) =>
      isHookRelatedExport(symbol.name),
    );
    const serviceSymbols = exportedSymbols.filter(
      (symbol) => !isHookRelatedExport(symbol.name),
    );

    const endpointImportPath = `../endpoints/${target.tag}/${target.moduleName}`;

    await fs.writeFile(
      path.join(SERVICES_DIR, `${target.tag}.ts`),
      buildExportModule({
        importPath: endpointImportPath,
        symbols: serviceSymbols,
      }),
    );
    serviceIndexExports.push(`./${target.tag}`);

    await fs.writeFile(
      path.join(HOOKS_DIR, `${target.tag}.ts`),
      buildExportModule({
        importPath: endpointImportPath,
        symbols: hookSymbols,
      }),
    );
    hookIndexExports.push(`./${target.tag}`);

    await fs.writeFile(
      path.join(ENDPOINTS_DIR, target.tag, "index.ts"),
      buildIndexFile([`./${target.moduleName}`]),
    );
    endpointIndexExports.push(`./${target.tag}`);
  }

  await fs.writeFile(
    path.join(SERVICES_DIR, "index.ts"),
    buildIndexFile(serviceIndexExports),
  );
  await fs.writeFile(path.join(HOOKS_DIR, "index.ts"), buildIndexFile(hookIndexExports));
  await fs.writeFile(
    path.join(ENDPOINTS_DIR, "index.ts"),
    buildIndexFile(endpointIndexExports),
  );

  await writeTypeIndex();

  await fs.writeFile(
    path.join(GENERATED_ROOT, "index.ts"),
    buildIndexFile(["./types", "./services", "./hooks", "./endpoints"]),
  );

  console.log(
    `[orval-layered-exports] processed ${endpointTargets.length} endpoint groups`,
  );
};

run().catch((error) => {
  console.error("[orval-layered-exports] failed:", error);
  process.exitCode = 1;
});
